const payload = $json.body ?? $json;
const action = String(payload.action ?? '').trim().toLowerCase();
const timezone = 'America/Argentina/Buenos_Aires';

function nowDateInTZ(tz) {
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  return fmt.format(new Date()); // YYYY-MM-DD
}

return [
  {
    json: {
      ...payload,
      action,
      timezone,
      request_ts: new Date().toISOString(),
      today_tz: nowDateInTZ(timezone),
    },
  },
];

const input = $json;
const requestedAction = String(input.action ?? '').trim().toLowerCase();
input.requested_action = requestedAction;

const allowedActions = new Set(['alta', 'search', 'influencers_search', 'consulta', 'extension', 'baja_manual', 'listar_ads', 'run_now', 'history', 'pause_ad', 'pause_active']);

function isValidDateFormat(value) {
  if (typeof value !== 'string') return false;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(value)) return false;
  const [y, m, d] = value.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d));
  return dt.getUTCFullYear() === y && dt.getUTCMonth() === (m - 1) && dt.getUTCDate() === d;
}

function toBool(value, fallback = false) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const normalized = String(value).trim().toLowerCase();
  return ['1', 'true', 'si', 'yes', 'y'].includes(normalized);
}

function badRequest(message, details = {}) {
  const err = new Error(message);
  err.name = 'ValidationError';
  err.details = details;
  throw err;
}

if (!allowedActions.has(requestedAction)) {
  badRequest('`action` invalida. Usar: alta | search | influencers_search | consulta | extension | baja_manual | listar_ads | run_now | history | pause_ad | pause_active', { action: input.action });
}

input.actor = String(input.requested_by ?? input.actor ?? 'ops@adskiller').trim();
input.correlation_id = String(input.correlation_id ?? `ak-ui-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);

if (requestedAction === 'search' || requestedAction === 'influencers_search') {
  const q = String(input.q ?? input.query ?? '').trim();
  if (!q) {
    badRequest('Falta `q` para search/influencers_search', { missing: ['q'] });
  }

  const limitRaw = Number(input.limit ?? 10);
  input.q = q;
  input.limit = Number.isFinite(limitRaw) && limitRaw > 0 ? Math.min(Math.trunc(limitRaw), 20) : 10;
  input.action = 'search';
}

if (requestedAction === 'alta') {
  const required = ['Contrato_ID', 'Cliente', 'Regex_Anuncio', 'Fecha_Fin'];
  const missing = required.filter((f) => !String(input[f] ?? '').trim());
  if (missing.length) {
    badRequest('Faltan campos obligatorios para alta', { missing });
  }

  if (!isValidDateFormat(input.Fecha_Fin)) {
    badRequest('Fecha_Fin inválida. Formato requerido: YYYY-MM-DD');
  }
}

if (requestedAction === 'extension') {
  const required = ['Contrato_ID', 'Nueva_Fecha_Fin'];
  const missing = required.filter((f) => !String(input[f] ?? '').trim());
  if (missing.length) {
    badRequest('Faltan campos obligatorios para extension', { missing });
  }

  if (!isValidDateFormat(input.Nueva_Fecha_Fin)) {
    badRequest('Nueva_Fecha_Fin inválida. Formato requerido: YYYY-MM-DD');
  }
}

if (requestedAction === 'consulta') {
  const dias = Number(input.dias_proximos ?? 7);
  if (!Number.isFinite(dias) || dias < 0 || dias > 365) {
    badRequest('dias_proximos inválido', { value: input.dias_proximos });
  }
  input.dias_proximos = Math.trunc(dias);
}

if (requestedAction === 'baja_manual') {
  const required = ['Contrato_ID'];
  const missing = required.filter((f) => !String(input[f] ?? '').trim());
  if (missing.length) {
    badRequest('Faltan campos obligatorios para baja_manual', { missing });
  }
}

if (requestedAction === 'listar_ads') {
