  }
}

if (requestedAction === 'run_now') {
  input.run_mode = String(input.run_mode ?? 'manual').trim().toLowerCase();
  input.dry_run = toBool(input.dry_run, false);
  input.confirm = toBool(input.confirm, false);
}

if (requestedAction === 'history') {
